/**
 * Returns a random fact from the given category array.
 * @param {string[]} categoryArray - One of the exported category arrays.
 * @returns {string}
 */
export function getRandomFact(categoryArray) {
  return categoryArray[Math.floor(Math.random() * categoryArray.length)];
}

/**
 * Returns a random fact from ALL_FACTS.
 * @returns {string}
 */
export function getRandomFactAny() {
  return ALL_FACTS[Math.floor(Math.random() * ALL_FACTS.length)];
}
